-- Base de démonstration ESP32 avec des dates anciennes
-- 48 mesures, une mesure tous les 7 jours
-- Première mesure : 2024-01-01 10:00:00
-- Dernière mesure : 2024-11-25 10:00:00

CREATE DATABASE IF NOT EXISTS esp32_supervision
CHARACTER SET utf8mb4
COLLATE utf8mb4_unicode_ci;

USE esp32_supervision;

CREATE TABLE IF NOT EXISTS measurements (
    id INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    temperature DECIMAL(6,2) NOT NULL,
    humidity DECIMAL(6,2) NOT NULL,
    resistance DECIMAL(12,6) NOT NULL,
    current_ma DECIMAL(10,4) DEFAULT NULL,
    created_at DATETIME NOT NULL,
    INDEX idx_measurements_created_at (created_at)
) ENGINE=InnoDB;

TRUNCATE TABLE measurements;

